462		// TODO webpack 6: solve this in a better way
463		// e.g. move compilation specific info from Modules into ModuleGraph
464		_cleanupLastCompilation() {
465			if (this._lastCompilation !== undefined) {
466				for (const childCompilation of this._lastCompilation.children) {
467					for (const module of childCompilation.modules) {
468						ChunkGraph.clearChunkGraphForModule(module);
469						ModuleGraph.clearModuleGraphForModule(module);
470						module.cleanupForCache();
471					}
472					for (const chunk of childCompilation.chunks) {
473						ChunkGraph.clearChunkGraphForChunk(chunk);
474					}
475				}
476	
477				for (const module of this._lastCompilation.modules) {
478					ChunkGraph.clearChunkGraphForModule(module);
479					ModuleGraph.clearModuleGraphForModule(module);
480					module.cleanupForCache();
481				}
482				for (const chunk of this._lastCompilation.chunks) {
483					ChunkGraph.clearChunkGraphForChunk(chunk);
484				}
485				this._lastCompilation = undefined;
486			}
487		}
